// Pterodactyl Game Stack Health Check
// Checks all infrastructure containers + game servers via Docker socket

const http = require('http');

function dockerGet(path) {
  return new Promise((resolve, reject) => {
    const opts = { socketPath: '/var/run/docker.sock', path, method: 'GET' };
    const req = http.request(opts, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve(data); } });
    });
    req.on('error', reject);
    req.end();
  });
}

const containers = await dockerGet('/containers/json?all=true');

// Infrastructure containers
const infra = ['pterodactyl-db', 'pterodactyl-cache', 'pterodactyl-panel', 'pterodactyl-wings'];
const ptero = {};

for (const name of infra) {
  const c = containers.find(c => c.Names.some(n => n === '/' + name));
  if (c) {
    ptero[name] = {
      id: c.Id,
      state: c.State,
      status: c.Status,
      healthy: c.State === 'running' && !c.Status.includes('unhealthy')
    };
  } else {
    ptero[name] = { id: null, state: 'missing', status: 'not found', healthy: false };
  }
}

// Game server containers (on pterodactyl_nw network, not infra)
const gameServers = containers.filter(c => {
  const nets = c.NetworkSettings && c.NetworkSettings.Networks;
  const onPteroNet = nets && nets.pterodactyl_nw;
  const isInfra = infra.some(name => c.Names.includes('/' + name));
  return onPteroNet && !isInfra;
});

const gsStatus = gameServers.map(c => ({
  id: c.Id,
  name: c.Names[0].replace('/', ''),
  state: c.State,
  status: c.Status
}));

return [{ json: { ptero, gameServers: gsStatus, timestamp: new Date().toISOString() } }];

// Classify failures by priority and type
const { ptero, gameServers } = $json;
const issues = [];

// Check dependency order: DB -> Cache -> Panel -> Wings
if (!ptero['pterodactyl-db'].healthy) {
  issues.push({ type: 'db_down', container: 'pterodactyl-db', containerId: ptero['pterodactyl-db'].id, severity: 'critical' });
}
if (!ptero['pterodactyl-cache'].healthy) {
  issues.push({ type: 'cache_down', container: 'pterodactyl-cache', containerId: ptero['pterodactyl-cache'].id, severity: 'high' });
}
if (!ptero['pterodactyl-panel'].healthy) {
  issues.push({ type: 'panel_down', container: 'pterodactyl-panel', containerId: ptero['pterodactyl-panel'].id, severity: 'high' });
}
if (!ptero['pterodactyl-wings'].healthy) {
  issues.push({ type: 'wings_down', container: 'pterodactyl-wings', containerId: ptero['pterodactyl-wings'].id, severity: 'critical' });
}

// Dead game servers
const deadGS = gameServers.filter(gs => gs.state !== 'running');
for (const gs of deadGS) {
  issues.push({ type: 'game_server_down', container: gs.name, containerId: gs.id, severity: 'high' });
}

// Wings stuck detection: check via Pterodactyl API
if (ptero['pterodactyl-wings'].healthy) {
  try {
    const panelUrl = 'http://pterodactyl-panel:80';
    const clientKey = 'h9xX34wBLNWuIna0Z71P1XrZowPOsXvyoPWKEHDx2LpjMmbM7IPg7tdmG5hQQkX4';
    const hdrs = { 'Authorization': 'Bearer ' + clientKey, 'Accept': 'application/json' };
    const data = await this.helpers.httpRequest({ method: 'GET', url: panelUrl + '/api/client', headers: hdrs, json: true });
    const servers = data.data || [];
    const staticData = $getWorkflowStaticData('global');
    if (!staticData.stuckServers) staticData.stuckServers = {};
    const now = Date.now();

    for (const srv of servers) {
      const id = srv.attributes.identifier;
      try {
        const resData = await this.helpers.httpRequest({ method: 'GET', url: panelUrl + '/api/client/servers/' + id + '/resources', headers: hdrs, json: true });
        const state = resData.attributes.current_state;
        if (state === 'starting' || state === 'stopping') {
          if (!staticData.stuckServers[id]) {
            staticData.stuckServers[id] = now;
          } else if (now - staticData.stuckServers[id] > 5 * 60 * 1000) {
            issues.push({ type: 'wings_stuck', container: 'pterodactyl-wings', containerId: ptero['pterodactyl-wings'].id, severity: 'critical', stuckServer: id, stuckState: state });
          }
        } else {
          delete staticData.stuckServers[id];
        }
      } catch(e) {}
    }
  } catch(e) {}
}

if (issues.length === 0) {
  return [{ json: { healthy: true, issues: [], timestamp: new Date().toISOString() } }];
}

return [{ json: { healthy: false, issues, timestamp: new Date().toISOString() } }];

