const panelUrl = 'http://pterodactyl-panel:80';
const clientKey = 'h9xX34wBLNWuIna0Z71P1XrZowPOsXvyoPWKEHDx2LpjMmbM7IPg7tdmG5hQQkX4';
const hdrs = { 'Authorization': 'Bearer ' + clientKey, 'Accept': 'application/json', 'Content-Type': 'application/json' };

for (const issue of issues) {
  const { type, container, containerId } = issue;

  // === Handler A: DB/Cache restart ===
  if (type === 'db_down' || type === 'cache_down') {
    let success = false;
    for (let attempt = 1; attempt <= 2; attempt++) {
      try {
        const result = await dockerPost('/containers/' + containerId + '/restart?t=30');
        if (result.status === 204) {
          await new Promise(r => setTimeout(r, 15000));
          success = true;
          break;
        }
      } catch(e) {}
    }
    results.push({ handler: 'support_restart', container, action: 'restart', result: success ? 'success' : 'failed', timestamp: new Date().toISOString() });
  }

  // === Handler B: Panel restart ===
  else if (type === 'panel_down') {
    let success = false;
    try {
      const result = await dockerPost('/containers/' + containerId + '/restart?t=30');
      if (result.status === 204) {
        await new Promise(r => setTimeout(r, 15000));
        success = true;
      }
    } catch(e) {}
    results.push({ handler: 'panel_restart', container, action: 'restart', result: success ? 'success' : 'failed', timestamp: new Date().toISOString() });
  }

  // === Handler C: Graceful Wings Recovery ===
  else if (type === 'wings_down' || type === 'wings_stuck') {
    const log = [];
    let runningServers = [];

    // Step 1: Get running servers from Panel
    try {
      const data = await this.helpers.httpRequest({ method: 'GET', url: panelUrl + '/api/client', headers: hdrs, json: true });
      const servers = data.data || [];
      for (const srv of servers) {
        const id = srv.attributes.identifier;
        try {
          const resData = await this.helpers.httpRequest({ method: 'GET', url: panelUrl + '/api/client/servers/' + id + '/resources', headers: hdrs, json: true });
          if (resData.attributes.current_state === 'running') {
            runningServers.push(id);
          }
        } catch(e) {}
      }
      log.push('Found ' + runningServers.length + ' running server(s)');

      // Step 2: Gracefully stop each
      for (const id of runningServers) {
        try {
          await this.helpers.httpRequest({ method: 'POST', url: panelUrl + '/api/client/servers/' + id + '/power', headers: hdrs, body: { signal: 'stop' } });
          log.push('Sent stop to ' + id);
        } catch(e) {
          log.push('Failed to stop ' + id + ': ' + e.message);
        }
      }
      if (runningServers.length > 0) {
        await new Promise(r => setTimeout(r, 30000));
        log.push('Waited 30s for graceful shutdown');
      }
    } catch(e) {
      log.push('Panel unreachable, skipping graceful stop: ' + e.message);
    }

    // Step 3: Restart Wings
    try {
      const containers = await dockerGet('/containers/json?all=true');
      const wings = containers.find(c => c.Names.some(n => n === '/pterodactyl-wings'));
      if (wings) {
        const result = await dockerPost('/containers/' + wings.Id + '/restart?t=60');
        log.push('Wings restart: ' + (result.status === 204 ? 'success' : 'failed (' + result.status + ')'));
        await new Promise(r => setTimeout(r, 15000));
        log.push('Waited 15s for Wings init');

        // Step 4: Re-start servers
        for (const id of runningServers) {
          try {
            await this.helpers.httpRequest({ method: 'POST', url: panelUrl + '/api/client/servers/' + id + '/power', headers: hdrs, body: { signal: 'start' } });
            log.push('Sent start to ' + id);
          } catch(e) {
            log.push('Failed to start ' + id + ': ' + e.message);
          }
        }
      } else {
        log.push('Wings container not found!');
      }
    } catch(e) {
      log.push('Wings restart error: ' + e.message);
    }

    results.push({ handler: 'wings_recovery', container, action: 'graceful_recovery', serversRestarted: runningServers, log, result: log.some(l => l.includes('success')) ? 'success' : 'partial', timestamp: new Date().toISOString() });
  }

  // === Handler D: Game Server Recovery ===
  else if (type === 'game_server_down') {
    const staticData = $getWorkflowStaticData('global');
    if (!staticData.crashHistory) staticData.crashHistory = {};
    const now = Date.now();
    const ONE_HOUR = 60 * 60 * 1000;

    if (!staticData.crashHistory[container]) {
      staticData.crashHistory[container] = { lastCrash: 0, crashCount: 0, cooldownUntil: 0, state: 'healthy' };
    }
    const record = staticData.crashHistory[container];

    if (now - record.lastCrash > ONE_HOUR && record.state !== 'crash_loop') {
      record.crashCount = 0;
      record.state = 'healthy';
    }

    if (record.cooldownUntil > now) {
      results.push({ handler: 'game_server_recovery', container, action: 'waiting_cooldown', cooldownRemaining: Math.round((record.cooldownUntil - now) / 1000) + 's', crashCount: record.crashCount, state: record.state, timestamp: new Date().toISOString() });
      continue;
    }

    if (record.state === 'crash_loop') {
      results.push({ handler: 'game_server_recovery', container, action: 'crash_loop_detected', crashCount: record.crashCount, state: 'crash_loop', timestamp: new Date().toISOString() });
      continue;
    }

    record.lastCrash = now;
    record.crashCount++;
    let action = 'restart';
    let result = 'pending';

    if (record.crashCount >= 3) {
      record.state = 'crash_loop';
      action = 'crash_loop_declared';
      result = 'gave_up';
    } else if (record.crashCount === 2) {
      record.cooldownUntil = now + 15 * 60 * 1000;
      record.state = 'recovering';
      action = 'cooldown_15min';
      result = 'scheduled';
    } else {
      record.cooldownUntil = now + 5 * 60 * 1000;
      record.state = 'recovering';
      action = 'cooldown_5min';
      result = 'scheduled';
    }

    results.push({ handler: 'game_server_recovery', container, action, result, crashCount: record.crashCount, state: record.state, timestamp: new Date().toISOString() });
  }
}

return results.map(r => ({ json: r }));

