const hdrs = { 'Authorization': 'Bearer ' + clientKey, 'Accept': 'application/json' };
const warnings = [];

try {
  const data = await this.helpers.httpRequest({ method: 'GET', url: panelUrl + '/api/client', headers: hdrs, json: true });
  const servers = data.data || [];

  for (const srv of servers) {
    const id = srv.attributes.identifier;
    const name = srv.attributes.name;

    try {
      const resData = await this.helpers.httpRequest({ method: 'GET', url: panelUrl + '/api/client/servers/' + id + '/resources', headers: hdrs, json: true });
      const attrs = resData.attributes;
      if (attrs.current_state === 'running' && attrs.resources) {
        const memUsed = attrs.resources.memory_bytes;
        const memLimit = attrs.resources.memory_limit_bytes;
        if (memLimit > 0) {
          const pct = Math.round((memUsed / memLimit) * 100);
          if (pct > 90) {
            warnings.push({ server: name, type: 'memory_high', detail: pct + '% memory used (' + Math.round(memUsed / 1024 / 1024) + 'MB / ' + Math.round(memLimit / 1024 / 1024) + 'MB)' });
          }
        }
      }
    } catch(e) {}
  }
} catch(e) {
  return [{ json: { mcHealthChecks: 'error', error: e.message } }];
}

if (warnings.length === 0) {
  return [{ json: { mcHealthChecks: 'all_clear', warnings: [] } }];
}

return [{ json: { mcHealthChecks: 'warnings_found', warnings, timestamp: new Date().toISOString() } }];

